Prometheus-client模块自定义metrics指标 特征维度 SDK（直接暴露） Exporter（转换代理） Pushgateway（推送中转） 数据流向 拉取 (Pull) 拉取 (Pull) 推送 → 暂存 → 拉取 (Push → Pull) 侵入性 高（需改代码） 无（独立进程） 低（调用推送API即可） 适用对象 可控的、自研的服务 不可控的、第三方的服务 生命周期短、无法被拉取的任务 模型契合度 完全契合 Prometheus 拉模型 完美契合，是拉模型的延伸 妥协方案，破坏了部分语义（如实例状态） 12345678910111213141516171819202122232425262728293031323334353637383940414243444546# python3.12.12pip install prometheus-clientfrom prometheus_client import start_http_server,Summary,Counterimport randomimport time# 定义计数器类型指标Counter# 标签：# user_type: 用户类型# login_status: 登录状态# ip_region：ip所属地区LOGIN_COUNT = Counter( &quot;user_login_total&quot;, # 指标名称 &#x27;用户登录总次数&#x27;, # 指标描述 [&#x27;user_type&#x27;, &#x27;login_status&#x27;, &#x27;ip_region&#x27;] # 标签)# 定义一个函数，模拟用户登录行为def simulate_login(): # 模拟用户类型 user_type = random.choices([&#x27;admin&#x27;, &#x27;user&#x27;], weights=[0.1, 0.9]) # 模拟登录状态 login_status = random.choices([&#x27;success&#x27;, &#x27;fail&#x27;], weights=[0.9, 0.1]) # 模拟IP地区 ip_region = random.choices([&#x27;china&#x27;, &#x27;usa&#x27;, &#x27;japan&#x27;,&#x27;korea&#x27;,&#x27;india&#x27;]) # 记录一次登录事件，每次吊用+1 LOGIN_COUNT.labels( user_type=user_type, login_status=login_status, ip_region=ip_region ).inc() if __name__ == &#x27;__main__&#x27;: # 启动http服务,端口为9092 start_http_server(9092) print(&quot;用户登录监控服务启动，端口：9092&quot;) while True: simulate_login() time.sleep(3) # 每三秒模拟一次用户登录行为# 运行脚本/root/miniconda3/envs/langchain/bin/python /root/prometheus-deepseek/custom_exporter.py用户登录监控服务启动，端口：9092 定义Prometheus抓取指标（传统方式）因为这里的服务并非k8s中的业务，所以没法使用serviceMonitor或者podMonitor，转而使用传统方式进行添加 对应到我使用的helm部署方式，就是在values.yaml的additionalScrapeConfigs中进行添加： 123456789101112 # 如果这个配置添加错误，会直接导致prometheus无法启动 additionalScrapeConfigs: - job_name: &#x27;user-login-monitor&#x27; static_configs: - targets: - &#x27;192.168.10.100:9092&#x27; scrape_interval: 30s scrape_timeout: 10s metrics_path: / scheme: http# 升级releasehelm upgrade prometheus ./ -f values.yaml 分类 语法&#x2F;操作符 示例 说明&#x2F;用途 基础查询 metric_name http_requests_total 即时查询，返回最新值 时间范围 [时间单位] [5m], [1h], [1d] 区间查询，单位：s,m,h,d,w,y 时间偏移 offset 时间 metric offset 1h 查询历史数据 标签过滤 &#123;label=&quot;value&quot;&#125; &#123;method=&quot;GET&quot;, status=&quot;200&quot;&#125; 精确匹配标签 标签过滤 &#123;label!=&quot;value&quot;&#125; &#123;status!=&quot;500&quot;&#125; 排除匹配标签 标签过滤 &#123;label=~&quot;regex&quot;&#125; &#123;job=~&quot;api.*&quot;&#125; 正则表达式匹配 标签过滤 &#123;label!~&quot;regex&quot;&#125; &#123;method!~&quot;POST.*&quot;&#125; 正则表达式排除 算术运算 + - * / % ^ requests * 2, errors/requests 数学运算 比较运算 == != &gt; &lt; &gt;= &lt;= response_time &gt; 1, errors != 0 条件筛选 聚合函数 sum() sum(http_requests_total) 求和 聚合函数 avg() avg(cpu_usage) 平均值 聚合函数 min()&#x2F;max() min(temp), max(memory) 最小&#x2F;最大值 聚合函数 count() count(instances) 计数 聚合函数 stddev() stddev(latency) 标准差 聚合分组 by(label) sum(...) by (method) 按标签分组聚合 聚合排除 without(label) avg(...) without (instance) 排除标签后聚合 速率函数 rate() rate(http_requests_total[5m]) 每秒平均增长率（Counter用） 瞬时速率 irate() irate(metric[5m]) 瞬时增长率（更敏感） 增长量 increase() increase(metric[1h]) 指定时间增长量 差值函数 delta() delta(temperature[2h]) Gauge类型差值 时间窗口 avg_over_time() avg_over_time(metric[5m]) 时间窗口平均值 时间窗口 max_over_time() max_over_time(metric[1h]) 时间窗口最大值 时间窗口 quantile_over_time() quantile_over_time(0.95, metric[30m]) 时间窗口分位数 数学函数 abs() abs(value) 绝对值 数学函数 ceil()&#x2F;floor() ceil(value), floor(value) 向上&#x2F;下取整 数学函数 round() round(value, 0.01) 四舍五入 数学函数 clamp_max()&#x2F;clamp_min() clamp_max(value, 100) 限制最大&#x2F;最小值 标签函数 label_replace() label_replace(metric, &quot;new&quot;, &quot;$1&quot;, &quot;old&quot;, &quot;(.*)&quot;) 替换标签值 标签函数 label_join() label_join(metric, &quot;new&quot;, &quot;,&quot;, &quot;label1&quot;, &quot;label2&quot;) 连接多个标签 时间函数 time() time() 当前时间戳 时间函数 timestamp() timestamp(metric) 指标时间戳 布尔修饰 bool metric &gt; bool 100 返回0&#x2F;1而非过滤 逻辑运算 and or unless metric1 and metric2 集合运算 注释 # # 这是注释 单行注释 配置告警规则12345678910111213141516171819202122232425262728# 创建PrometheusRule，user-login-monitor.yaml---apiVersion: monitoring.coreos.com/v1kind: PrometheusRulemetadata: name: user-login-alert-rules labels: release: prometheus # 匹配的选择器spec: groups: rules: - alert: UserLoginFailedRate expr: | sum(rate(user_login_total&#123;login_status=&quot;[&#x27;fail&#x27;]&quot;&#125;[1m])) / sum(rate(user_login_total[1m])) &gt; 0.05 # 失败总数/登录总数，失败错误率 &gt; 5%就报警 for: 2m labels: severity: warning # 告警级别 ip_region: &quot;&#123;&#123; $labels.ip_region &#125;&#125;&quot; # 自定义标签 user_type: &quot;&#123;&#123; $labels.user_type &#125;&#125;&quot; # 自定义标签 annotations: summary: &quot;用户登录失败率过高&quot; description: &quot;用户登录失败率 &#123;&#123; $value &#125;&#125; &gt; 5%，持续 2 分钟&quot;kubectl apply -f user-login-monitor.yaml# 并重启prometheus 配置altermanager转发Alertmanager的路由是基于标签匹配的 123456789101112131415161718192021222324252627282930313233343536373839404142434445alertmanager.yml├── global: # 全局设置├── route: # 路由设置│ ├── receiver: # 默认接收器（名称）│ ├── group_by: # 分组设置│ └── routes: # 子路由列表│ └── receiver: # 子路由接收器（名称）└── receivers: # 接收器定义列表 ├── name: &#x27;default-email&#x27; └── name: &#x27;webhook_handler&#x27; alertmanager: config: global: resolve_timeout: 5m smtp_smarthost: &#x27;smtp.163.com:25&#x27; smtp_from: &#x27;alertwarning@163.com&#x27; smtp_auth_username: &#x27;alertwarning@163.com&#x27; smtp_auth_password: &#x27;GAANBCIHILSARBYD&#x27; smtp_require_tls: false route: # 根路由，若告警未匹配任何子路由，则直接使用根路由的receiver，即默认路由 receiver: &#x27;default-email&#x27; group_wait: 10s # 触发告警后等待10秒，若同组有其他告警则合并发送 group_interval: 1m repeat_interval: 5m routes: - receiver: &#x27;webhook_handler&#x27; # 所有warning告警 → webhook matchers: # 标签匹配 - severity = &quot;warning&quot; continue: false # 是否继续匹配 receivers: # 接收器配置 - name: &#x27;default-email&#x27; email_configs: - to: &#x27;1320991378@qq.com&#x27; send_resolved: true headers: Subject: &#x27;Alert: &#123;&#123; .CommonLabels.alertname &#125;&#125;&#x27; - name: &#x27;webhook_handler&#x27; webhook_configs: - url: &#x27;http://192.168.10.100:5008/alter&#x27; # 告警处理服务地址，设置为本机5008端口 send_resolved: truehelm upgrade prometheus ./ -f values.yamlkubectl rollout restart statefulset prometheus-prometheus-kube-prometheus-prometheus 处理告警并发送给Deepseekaltermanager发送的信息123456789101112131415161718192021222324252627282930313233343536373839# 此时接收到的json数据是这样的# 可见alerts是一个列表，里面放的是聚合告警，我这里只有一个告警，所以没有体现。但实际上应该去遍历&#123; &quot;receiver&quot;: &quot;webhook_handler&quot;, &quot;status&quot;: &quot;firing&quot;, &quot;alerts&quot;: [ &#123; &quot;status&quot;: &quot;firing&quot;, &quot;labels&quot;: &#123; &quot;alertname&quot;: &quot;UserLoginFailedRate&quot;, &quot;prometheus&quot;: &quot;default/prometheus-kube-prometheus-prometheus&quot;, &quot;severity&quot;: &quot;warning&quot; &#125;, &quot;annotations&quot;: &#123; &quot;description&quot;: &quot;用户登录失败率 0.23333333333333334 &gt; 5%，持续 2 分钟&quot;, &quot;summary&quot;: &quot;用户登录失败率过高&quot; &#125;, &quot;startsAt&quot;: &quot;2026-01-20T02:50:48.671Z&quot;, &quot;endsAt&quot;: &quot;0001-01-01T00:00:00Z&quot;, &quot;generatorURL&quot;: &quot;http://prometheus-kube-prometheus-prometheus.default:9090/graph?g0.expr=sum%28rate%28user_login_total%7Blogin_status%3D%22%5B%27fail%27%5D%22%7D%5B1m%5D%29%29+%2F+sum%28rate%28user_login_total%5B1m%5D%29%29+%3E+0.05&amp;g0.tab=1&quot;, &quot;fingerprint&quot;: &quot;4c7fe64e5b33b2f8&quot; &#125; ], &quot;groupLabels&quot;: &#123;&#125;, &quot;commonLabels&quot;: &#123; &quot;alertname&quot;: &quot;UserLoginFailedRate&quot;, &quot;prometheus&quot;: &quot;default/prometheus-kube-prometheus-prometheus&quot;, &quot;severity&quot;: &quot;warning&quot; &#125;, &quot;commonAnnotations&quot;: &#123; &quot;description&quot;: &quot;用户登录失败率 0.23333333333333334 &gt; 5%，持续 2 分钟&quot;, &quot;summary&quot;: &quot;用户登录失败率过高&quot; &#125;, &quot;externalURL&quot;: &quot;http://prometheus-kube-prometheus-alertmanager.default:9093&quot;, &quot;version&quot;: &quot;4&quot;, &quot;groupKey&quot;: &quot;&#123;&#125;/&#123;severity=\&quot;warning\&quot;&#125;:&#123;&#125;&quot;, &quot;truncatedAlerts&quot;: 0&#125; 创建alerts处理程序123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108from datetime import date, datetimeimport os# 定义loggerimport loggingcurrent_dir = os.path.dirname(os.path.abspath(__file__))alerts_log = os.path.join(current_dir, &#x27;alerts.log&#x27;) # 告警日志文件路径alter_report = os.path.join(current_dir, &#x27;alter_report.txt&#x27;) # 告警报告文件路径format = &#x27;%(asctime)s - %(levelname)s - %(message)s&#x27; # 定义日志格式logging.basicConfig(filename=alerts_log,filemode=&#x27;a&#x27;,format=format,level=logging.INFO)# 初始化Deepseekfrom langchain_deepseek import ChatDeepSeekfrom dotenv import load_dotenvload_dotenv()def call_deepseek(message): deepseek = ChatDeepSeek(model=&quot;deepseek-chat&quot;,temperature=0.5) logging.debug(f&quot;Deepseek初始化完成...&quot;) system_prompt = &quot;&quot;&quot; 你是一名资深运维与安全分析师，擅长分析业务系统异常告警。 请根据提供的登录监控告警信息，生成结构化分析报告，包含： 1. 告警基本信息（名称、级别、时间、关键标签） 2. 可能的原因分析（结合业务场景，如攻击、系统故障、用户行为异常等） 3. 具体处理建议（分步骤说明，可操作） 4. 预防措施（如何避免类似问题再次发生） 报告风格需专业、简洁，重点突出。 &quot;&quot;&quot; user_prompt = f&quot;&quot;&quot; 告警详细信息如下： &#123;message&#125; &quot;&quot;&quot; messages = [system_prompt,user_prompt] response = deepseek.invoke(messages) with open(alter_report, &quot;w&quot;, encoding=&quot;utf-8&quot;) as f: f.write(f&quot;[&#123;datetime.now()&#125;] DeepSeek报告：
&quot;) f.write(f&quot;&#123;response.content&#125;&quot;) logging.info(f&quot;DeepSeek响应已保存至 &#123;alter_report&#125;&quot;) # 定义flask框架、路由from flask import Flask, request, jsonifyapp = Flask(__name__) @app.route(&#x27;/alter&#x27;, methods=[&#x27;POST&#x27;])def handle_alert(): try: data = request.get_json() # 确保数据包含 alerts 字段 if &#x27;alerts&#x27; not in data: logging.error(&quot;数据格式错误：缺少 alerts 字段&quot;) return jsonify(&#123;&quot;status&quot;: &quot;error&quot;, &quot;message&quot;: &quot;Invalid data format: missing alerts field&quot;&#125;), 400 # 确保 alerts 字段是一个列表 if not isinstance(data[&#x27;alerts&#x27;], list): logging.error(&quot;数据格式错误：alerts 字段不是列表&quot;) return jsonify(&#123;&quot;status&quot;: &quot;error&quot;, &quot;message&quot;: &quot;alerts field is not a list&quot;&#125;), 400 logging.info(&quot;成功接收到告警数据...&quot;) alerts_list = data[&#x27;alerts&#x27;] all_messages = [] # 遍历 alerts 列表，提取每个告警的详细信息 for alert in alerts_list: # 提取 annotations 中的 description 和 summary logging.debug(&quot;开始解析告警信息...&quot;) annotations = alert.get(&#x27;annotations&#x27;, &#123;&#125;) description = annotations.get(&#x27;description&#x27;, &#x27;No description provided&#x27;) summary = annotations.get(&#x27;summary&#x27;, &#x27;No summary provided&#x27;) # 提取 labels 中的关键信息 labels = alert.get(&#x27;labels&#x27;, &#123;&#125;) alert_name = labels.get(&#x27;alertname&#x27;, &#x27;Unknown&#x27;) severity = labels.get(&#x27;severity&#x27;, &#x27;Unknown&#x27;) # 提取时间信息 starts_at = alert.get(&#x27;startsAt&#x27;, &#x27;Unknown&#x27;) status = alert.get(&#x27;status&#x27;, &#x27;Unknown&#x27;) # 将信息整合为message message = f&quot;告警名称: &#123;alert_name&#125;
